def gen(rng, size):
    n = max(2, min(2000, size))
    edges = []
    for i in range(1, n):
        p = rng.randint(0, i - 1)
        edges.append([p, i])
    guesses = []
    for a, b in edges:
        if rng.random() < 0.6:
            if rng.random() < 0.5:
                guesses.append([a, b])
            else:
                guesses.append([b, a])
    if not guesses:
        guesses.append(edges[0])
    k = rng.randint(0, len(guesses))
    return [edges, guesses, k]

