class Solution:
    def rootCount(self, edges, guesses, k):
        from collections import defaultdict, deque
        n = len(edges) + 1
        adj = defaultdict(list)
        for a, b in edges:
            adj[a].append(b)
            adj[b].append(a)
        total = 0
        for root in range(n):
            parent = {root: -1}
            dq = deque([root])
            visited = {root}
            while dq:
                u = dq.popleft()
                for v in adj[u]:
                    if v not in visited:
                        visited.add(v)
                        parent[v] = u
                        dq.append(v)
            correct = sum(1 for u, v in guesses if parent.get(v) == u)
            if correct >= k:
                total += 1
        return total

