class Solution:
    def rootCount(self, edges, guesses, k):
        from collections import defaultdict, deque
        n = len(edges) + 1
        adj = defaultdict(list)
        for a, b in edges:
            adj[a].append(b)
            adj[b].append(a)
        guess_set = set((u, v) for u, v in guesses)
        parent = [-1] * n
        order = []
        visited = [False] * n
        visited[0] = True
        stack = [0]
        while stack:
            u = stack.pop()
            order.append(u)
            for v in adj[u]:
                if not visited[v]:
                    visited[v] = True
                    parent[v] = u
                    stack.append(v)
        base = sum(1 for (u, v) in guess_set if parent[v] == u)
        cnt = [0] * n
        cnt[0] = base
        dq = deque([0])
        while dq:
            u = dq.popleft()
            for v in adj[u]:
                if v == parent[u]:
                    continue
                delta = 0
                if (u, v) in guess_set:
                    delta -= 1
                if (v, u) in guess_set:
                    delta += 1
                cnt[v] = cnt[u] + delta
                dq.append(v)
        return sum(1 for c in cnt if c >= k)

