var rootCount = function(edges, guesses, k) {
    const n = edges.length + 1;
    const adj = Array.from({ length: n }, () => []);
    for (const [a, b] of edges) {
        adj[a].push(b);
        adj[b].push(a);
    }
    const guessSet = new Set(guesses.map(([u, v]) => u + ',' + v));
    const parent = new Array(n).fill(-1);
    const order = [];
    const visited = new Array(n).fill(false);
    visited[0] = true;
    const stack = [0];
    while (stack.length) {
        const u = stack.pop();
        order.push(u);
        for (const v of adj[u]) {
            if (!visited[v]) {
                visited[v] = true;
                parent[v] = u;
                stack.push(v);
            }
        }
    }
    let base = 0;
    for (const key of guessSet) {
        const [u, v] = key.split(',').map(Number);
        if (parent[v] === u) base += 1;
    }
    const cnt = new Array(n).fill(0);
    cnt[0] = base;
    const queue = [0];
    let head = 0;
    while (head < queue.length) {
        const u = queue[head++];
        for (const v of adj[u]) {
            if (v === parent[u]) continue;
            let delta = 0;
            if (guessSet.has(u + ',' + v)) delta -= 1;
            if (guessSet.has(v + ',' + u)) delta += 1;
            cnt[v] = cnt[u] + delta;
            queue.push(v);
        }
    }
    return cnt.filter((c) => c >= k).length;
};
